final:
module decoder_2to4 (output_inverted, a, en);
   input [1:0] a;
   input en;
   output [3:0] output_inverted;

   reg [3:0] output_inverted;

always @(a or en) begin
    if (!en)
        output_inverted = 4'b0000;
    else begin
        case (a)
            2'b00: output_inverted = 4'b0001;
            2'b01: output_inverted = 4'b0010;
            2'b10: output_inverted = 4'b0100;
            2'b11: output_inverted = 4'b1000;
            default: output_inverted = 4'b0000;
        endcase
    end
end

endmodule
